def words_in_sentence(sentence):
    """Return words with prime lengths from the given sentence."""
    words = sentence.split()  # Split the sentence into words
    prime_length_words = [word for word in words if is_prime(len(word))]  # Filter words with prime lengths
    return ' '.join(prime_length_words)  # Join the filtered words back into a string

